import type { SupabaseClient } from "@supabase/supabase-js";
import type { NavigationItem, NavigationItemInsert, NavigationItemUpdate } from "../types";

export async function createNavigationItem(
  supabase: SupabaseClient,
  data: NavigationItemInsert,
) {
  const { data: item, error } = await supabase
    .from("navigation_items")
    .insert(data)
    .select()
    .single();

  if (error) throw error;
  return item as NavigationItem;
}

export async function updateNavigationItem(
  supabase: SupabaseClient,
  id: string,
  data: NavigationItemUpdate,
) {
  const { data: item, error } = await supabase
    .from("navigation_items")
    .update(data)
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;
  return item as NavigationItem;
}

export async function deleteNavigationItem(
  supabase: SupabaseClient,
  id: string,
) {
  const { error } = await supabase
    .from("navigation_items")
    .delete()
    .eq("id", id);
  if (error) throw error;
}

export async function reorderNavigationItems(
  supabase: SupabaseClient,
  orderedIds: string[],
) {
  const updates = orderedIds.map((id, index) =>
    supabase.from("navigation_items").update({ sort_order: index }).eq("id", id),
  );
  await Promise.all(updates);
}
