export async function reorderPageBlocks(
  supabase: SupabaseClient,
  orderedIds: string[],
) {
  const updates = orderedIds.map((id, index) =>
    supabase.from("page_blocks").update({ sort_order: index }).eq("id", id),
  );
  await Promise.all(updates);
}
