import type { SupabaseClient } from "@supabase/supabase-js";
import type { HomepageConfig, HomepageConfigUpdate } from "../types";

export async function upsertHomepageConfig(
  supabase: SupabaseClient,
  data: HomepageConfigUpdate,
) {
  // Get existing config id
  const { data: existing } = await supabase
    .from("homepage_config")
    .select("id")
    .limit(1)
    .maybeSingle();

  if (existing) {
    const { data: updated, error } = await supabase
      .from("homepage_config")
      .update({ ...data, updated_at: new Date().toISOString() })
      .eq("id", existing.id)
      .select()
      .single();

    if (error) throw error;
    return updated as HomepageConfig;
  }

  const { data: created, error } = await supabase
    .from("homepage_config")
    .insert(data)
    .select()
    .single();

  if (error) throw error;
  return created as HomepageConfig;
}
