import type { SupabaseClient } from "@supabase/supabase-js";
import type { Media } from "../types";

const BUCKET_NAME = "cms-media";

/**
 * Upload a file to Supabase Storage and record it in the media table.
 */
export async function uploadMedia(
  supabase: SupabaseClient,
  file: File,
  options: { altText?: string; folder?: string } = {},
) {
  const { altText, folder = "uploads" } = options;

  // Generate unique filename
  const timestamp = Date.now();
  const safeName = file.name.replace(/[^a-zA-Z0-9.-]/g, "_");
  const storagePath = `${folder}/${timestamp}-${safeName}`;

  // Upload to Supabase Storage
  const { error: uploadError } = await supabase.storage
    .from(BUCKET_NAME)
    .upload(storagePath, file, {
      cacheControl: "3600",
      upsert: false,
    });

  if (uploadError) throw uploadError;

  // Get public URL
  const {
    data: { publicUrl },
  } = supabase.storage.from(BUCKET_NAME).getPublicUrl(storagePath);

  // Get current user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  // Insert into media table
  const { data: media, error: dbError } = await supabase
    .from("media")
    .insert({
      filename: file.name,
      storage_path: storagePath,
      url: publicUrl,
      mime_type: file.type,
      size_bytes: file.size,
      alt_text: altText ?? null,
      uploaded_by: user?.id ?? null,
    })
    .select()
    .single();

  if (dbError) throw dbError;
  return media as Media;
}

/**
 * Delete a media file from storage and database.
 */
export async function deleteMedia(
  supabase: SupabaseClient,
  id: string,
) {
  // Get the media record first
  const { data: media, error: fetchError } = await supabase
    .from("media")
    .select("storage_path")
    .eq("id", id)
    .single();

  if (fetchError) throw fetchError;

  // Remove from storage
  if (media) {
    const { error: storageError } = await supabase.storage
      .from(BUCKET_NAME)
      .remove([media.storage_path]);

    if (storageError) throw storageError;
  }

  // Remove from database
  const { error: dbError } = await supabase
    .from("media")
    .delete()
    .eq("id", id);

  if (dbError) throw dbError;
}

/**
 * Get all media files, ordered by most recent.
 */
export async function getMediaFiles(
  supabase: SupabaseClient,
  options: { limit?: number; offset?: number; search?: string } = {},
) {
  const { limit = 50, offset = 0, search } = options;

  let query = supabase
    .from("media")
    .select("*", { count: "exact" })
    .order("created_at", { ascending: false })
    .range(offset, offset + limit - 1);

  if (search) {
    query = query.ilike("filename", `%${search}%`);
  }

  const { data, error, count } = await query;

  if (error) throw error;
  return { media: (data as Media[]) ?? [], total: count ?? 0 };
}
