import type { SupabaseClient } from "@supabase/supabase-js";
import type { Article, ArticleInsert, ArticleUpdate } from "../types";
import { calculateReadingTime } from "../utils/reading-time";

/**
 * Create a new article.
 */
export async function createArticle(
  supabase: SupabaseClient,
  data: ArticleInsert,
  tagIds?: string[],
) {
  // Calculate reading time if content_html is provided
  const reading_time_minutes = data.content_html
    ? calculateReadingTime(data.content_html)
    : null;

  const { data: article, error } = await supabase
    .from("articles")
    .insert({ ...data, reading_time_minutes })
    .select()
    .single();

  if (error) throw error;

  // Link tags if provided
  if (tagIds && tagIds.length > 0 && article) {
    const tagRelations = tagIds.map((tag_id) => ({
      article_id: article.id,
      tag_id,
    }));

    const { error: tagError } = await supabase
      .from("article_tags")
      .insert(tagRelations);

    if (tagError) throw tagError;
  }

  return article as Article;
}

/**
 * Update an existing article.
 */
export async function updateArticle(
  supabase: SupabaseClient,
  id: string,
  data: ArticleUpdate,
  tagIds?: string[],
) {
  // Recalculate reading time if content_html changed
  const updates: ArticleUpdate & { reading_time_minutes?: number | null } = {
    ...data,
  };
  if (data.content_html) {
    updates.reading_time_minutes = calculateReadingTime(data.content_html);
  }

  const { data: article, error } = await supabase
    .from("articles")
    .update(updates)
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;

  // Update tags if provided
  if (tagIds !== undefined) {
    // Remove existing tags
    await supabase.from("article_tags").delete().eq("article_id", id);

    // Insert new tags
    if (tagIds.length > 0) {
      const tagRelations = tagIds.map((tag_id) => ({
        article_id: id,
        tag_id,
      }));

      const { error: tagError } = await supabase
        .from("article_tags")
        .insert(tagRelations);

      if (tagError) throw tagError;
    }
  }

  return article as Article;
}

/**
 * Delete an article.
 */
export async function deleteArticle(
  supabase: SupabaseClient,
  id: string,
) {
  const { error } = await supabase.from("articles").delete().eq("id", id);

  if (error) throw error;
}

/**
 * Publish an article (set status to published, set published_at to now).
 */
export async function publishArticle(
  supabase: SupabaseClient,
  id: string,
) {
  const { data, error } = await supabase
    .from("articles")
    .update({
      status: "published",
      published_at: new Date().toISOString(),
    })
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;
  return data as Article;
}

/**
 * Schedule an article for future publication.
 */
export async function scheduleArticle(
  supabase: SupabaseClient,
  id: string,
  scheduledAt: string,
) {
  const { data, error } = await supabase
    .from("articles")
    .update({
      status: "scheduled",
      scheduled_at: scheduledAt,
    })
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;
  return data as Article;
}

/**
 * Archive an article.
 */
export async function archiveArticle(
  supabase: SupabaseClient,
  id: string,
) {
  const { data, error } = await supabase
    .from("articles")
    .update({ status: "archived" })
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;
  return data as Article;
}

/**
 * Revert article to draft.
 */
export async function unpublishArticle(
  supabase: SupabaseClient,
  id: string,
) {
  const { data, error } = await supabase
    .from("articles")
    .update({
      status: "draft",
      published_at: null,
      scheduled_at: null,
    })
    .eq("id", id)
    .select()
    .single();

  if (error) throw error;
  return data as Article;
}
