import type { SupabaseClient } from "@supabase/supabase-js";
import type { Page } from "../types";

export async function getPages(
  supabase: SupabaseClient,
  options: { includeBlocks?: boolean; includeDrafts?: boolean } = {},
) {
  const { includeBlocks = false, includeDrafts = false } = options;

  let query = supabase
    .from("pages")
    .select("*")
    .order("title", { ascending: true });

  if (!includeDrafts) {
    query = query.eq("status", "published");
  }

  const { data, error } = await query;
  if (error) throw error;

  // If blocks requested, fetch them separately to avoid PostgREST type conflicts
  const pages = (data as unknown as Page[]) ?? [];

  if (includeBlocks && pages.length > 0) {
    const pageIds = pages.map((p) => p.id);
    const { data: blocks } = await supabase
      .from("page_blocks")
      .select("*")
      .in("page_id", pageIds)
      .order("sort_order", { ascending: true });

    return pages.map((p) => ({
      ...p,
      blocks: (blocks ?? []).filter((b) => b.page_id === p.id),
    }));
  }

  return pages;
}

export async function getPageBySlug(
  supabase: SupabaseClient,
  slug: string,
  options: { includeDrafts?: boolean } = {},
) {
  const { includeDrafts = false } = options;

  let query = supabase
    .from("pages")
    .select("*")
    .eq("slug", slug);

  if (!includeDrafts) {
    query = query.eq("status", "published");
  }

  const { data, error } = await query.maybeSingle();
  if (error) throw error;
  if (!data) return null;

  const page = data as unknown as Page;

  // Fetch blocks separately
  const { data: blocks } = await supabase
    .from("page_blocks")
    .select("*")
    .eq("page_id", page.id)
    .order("sort_order", { ascending: true });

  return { ...page, blocks: blocks ?? [] };
}

export async function getPageById(
  supabase: SupabaseClient,
  id: string,
) {
  const { data, error } = await supabase
    .from("pages")
    .select("*")
    .eq("id", id)
    .single();

  if (error) throw error;
  const page = data as unknown as Page;

  // Fetch blocks separately
  const { data: blocks } = await supabase
    .from("page_blocks")
    .select("*")
    .eq("page_id", id)
    .order("sort_order", { ascending: true });

  return { ...page, blocks: blocks ?? [] };
}
